import React from 'react';
import { Dialog as CarbonDialog } from '@carbon/react';

const Dialog = (props) => {
    const {
        id,
        setProps,
        children,
        className,
        ...otherProps
    } = props;

    return (
        <CarbonDialog
            id={id}
            className={className}
            {...otherProps}
        >
            {children}
        </CarbonDialog>
    );
};

Dialog.defaultProps = {
    className: ''
};

export default Dialog;
